{"command":"# Since the database is at `comfyui-db`, and I am in a local environment, 
# it seems the hostname `comfyui-db` is not resolvable from this shell.
# I will try to use `localhost` instead, as it might be mapped or accessible via a different route.
# However, the user mentioned an IP in their message: http://192.168.1.100:3001/admin/workflows
# This suggests the system might be accessible via 192.168.1.100 or similar.

# Let's try to use the IP address from the user's message if it can be used as a host.
# But usually, database hosts are different from the web server host.

# Let's try to use 127.0.0.1 instead of localhost (sometimes there's a difference in how they resolve).
# Or better, let's try to find the IP of comfyui-db if we can.

# Since I cannot resolve hostnames, let's try to see if there is any other way.
# I will try to use the IP 192.168.1.76 (from HOST_IP in .env) as the host for the database.

cat <<EOF > query_tasks.js
const { PrismaClient } = require('@prisma/client');
process.env.DATABASE_URL = 'postgresql://comfyui:comfyui_pass_2026@192.168.1.76:5432/comfyui';
const prisma = new PrismaClient();

async function main() {
  try {
    const failedTasks = await prisma.task.findMany({
      where: { status: 'failed' },
      orderBy: { id: 'desc' },
      take: 5
    });
    console.log('--- Failed Tasks ---');
    failedTasks.forEach(task => {
      console.log(\`ID: \${task.id}\`);
      console.log(\`Error: \${task.error || 'N/A'}\`);
      console.log(\`ErrorDetail: \${task.errorDetail || 'N/A'}\`);
      console.log(\`Prompt: \${task.prompt}\`);
      console.log('--------------------');
    });
  } catch (e) {
    console.error("Error during query:", e);
  } finally {
    await prisma.\$disconnect();
  }
}

main();
EOF

node query_tasks.js"}
